def best_match_in_quran(query):
    best=None
    qn=normalize_arabic(query)
    for rec in quran:
        text=rec['ayah_text']
        rn=normalize_arabic(text)
        r=ratio(qn, rn)
        if not best or r>best[0]:
            best=(r, rec)
    return best

def best_match_in_hadith(query):
    best=None
    qn=normalize_arabic(query)
    for rec in hadith:
        for field in ['hadithTxt','Matn']:
            text=rec.get(field) or ''
            if not text:
                continue
            rn=normalize_arabic(text)
            r=ratio(qn, rn)
            if not best or r>best[0]:
                best=(r, rec, field)
    return best

